import "./button.css";

import type React from "react";

import { cn } from "tailwind-variants";

import { buttonVariants, type ButtonVariants } from "./button.variants";

export interface ButtonProps extends ButtonVariants, React.ComponentProps<"button"> {}

export const Button = ({
  children,
  className,
  isIconOnly,
  size,
  variant,
  ...props
}: ButtonProps) => {
  const styles = cn(buttonVariants({ isIconOnly, size, variant }), className);

  return (
    <button className={styles} {...props}>
      {children}
    </button>
  );
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const buttonVariants = tv({
  base: "button",
  variants: {
    variant: {
      primary: "button--primary",
      secondary: "button--secondary",
      ghost: "button--ghost",
      outline: "button--outline",
      destructive: "button--destructive",
    },
    size: {
      sm: "button--sm",
      md: "button--md",
      lg: "button--lg",
    },
    isIconOnly: {
      true: "button--icon-only",
      false: "",
    },
  },
  defaultVariants: {
    variant: "primary",
    size: "md",
    isIconOnly: false,
  },
});

export type ButtonVariants = VariantProps<typeof buttonVariants>;

.button {
  @apply inline-flex items-center justify-center gap-2 rounded-md font-medium whitespace-nowrap transition-colors;

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply pointer-events-none opacity-50;
  }
}

.button--primary {
  @apply bg-primary text-primary-foreground;

  &:hover {
    @apply bg-primary/90;
  }
}

.button--destructive {
  @apply bg-destructive text-white;

  &:hover {
    @apply bg-destructive/90;
  }
}

.button--secondary {
  @apply bg-secondary text-secondary-foreground;

  &:hover {
    @apply bg-secondary/80;
  }
}

.button--ghost {
  &:hover {
    @apply bg-accent text-accent-foreground;
  }
}

.button--outline {
  @apply border-input bg-background border;

  &:hover {
    @apply bg-accent text-accent-foreground;
  }
}

.button--sm {
  @apply h-8 rounded-md px-3 text-xs;
}

.button--md {
  @apply h-9 px-4 text-sm;
}

.button--lg {
  @apply h-10 px-6 text-base;
}

.button--icon-only {
  @apply aspect-square px-0;
}

import { Button, type ButtonProps } from "./button";
import { type ButtonVariants, buttonVariants } from "./button.variants";

export { Button, buttonVariants };

export type { ButtonProps, ButtonVariants };
